previewCss:
.darma-loader-uiverse-aurora-jump-pearls {
  position: relative;
  display: flex;
  gap: 0.3em;
}

.darma-loader-uiverse-aurora-jump-pearls::before {
content: "";
position: absolute;
left: 0;
top: 0;
width: 100%;
height: 2em;
filter: blur(45px);
background-color: var(--loader-secondary-color, #e299ff);
background-image: radial-gradient(at 52% 57%, hsla(11,83%,72%,1) 0px, transparent 50%),
radial-gradient(at 37% 57%, hsla(175,78%,66%,1) 0px, transparent 50%);
}

.darma-loader-uiverse-aurora-jump-pearls___circle {
--size-loader: 0.6em;
width: var(--size-loader);
height: var(--size-loader);
border-radius: 50%;
animation: darma-loader-uiverse-aurora-jump-pearls-loaderCircleJumping 2s infinite;
background-color: var(--loader-color, #b499ff);
}

.darma-loader-uiverse-aurora-jump-pearls___circle:nth-child(2n) {
animation-delay: 300ms;
background-color: #e499ff;
}

.darma-loader-uiverse-aurora-jump-pearls___circle:nth-child(3n) {
animation-delay: 600ms;
}

@keyframes darma-loader-uiverse-aurora-jump-pearls-loaderCircleJumping {
0%, 100% {
transform: translateY(0px);
}

25% {
transform: translateY(-15px) scale(0.5);
}

50% {
transform: translateY(0px);
}

75% {
transform: translateY(5px) scale(0.9);
}
}

